#!/bin/bash
set -euo pipefail
cd /root/ARCARNA

mkdir -p "$(dirname 'server/routes/v1.ts')"
python3 - <<'PYEOF'
import base64, pathlib
p = pathlib.Path('server/routes/v1.ts')
p.write_bytes(base64.b64decode(''))
print('Wrote', p, 'bytes=', p.stat().st_size)
PYEOF

mkdir -p "$(dirname 'server/middleware/apiKeyAuth.ts')"
python3 - <<'PYEOF'
import base64, pathlib
p = pathlib.Path('server/middleware/apiKeyAuth.ts')
p.write_bytes(base64.b64decode(''))
print('Wrote', p, 'bytes=', p.stat().st_size)
PYEOF

grep -n registerV1Routes server/routes.ts || { echo 'ERROR: registerV1Routes missing from server/routes.ts'; exit 1; }
npm run build
pm2 restart ARCARNA
sleep 5
curl -s http://127.0.0.1:5000/api/health || true
echo
echo 'Done:'
wc -l server/routes/v1.ts server/middleware/apiKeyAuth.ts
